function solve(grid, x, y, k) {
    // Create a deep copy of the grid to avoid modifying the original directly
    const newGrid = grid.map(row => [...row]);

    // Iterate over the rows in the submatrix that need to be reversed
    for (let i = 0; i < Math.floor(k / 2); i++) {
        const row1 = x + i;
        const row2 = x + k - 1 - i;

        // Swap the rows row1 and row2 within the submatrix columns [y, y + k - 1]
        for (let col = y; col < y + k; col++) {
            const temp = newGrid[row1][col];
            newGrid[row1][col] = newGrid[row2][col];
            newGrid[row2][col] = temp;
        }
    }

    return newGrid;
}

